record.field:
{
            "type": "object",
            "properties": {
                "name": { "type": "string", "description": "Description of the expense (e.g., 'Lunch with client')" },
                "total_amount_currency": { "type": "number", "description": "Total amount in the given currency" },
                "currency_id": { "type": "string", "description": "Currency code (e.g., 'PHP', 'USD')" },
                "date": { "type": "string", "format": "date", "description": "Date of the expense (YYYY-MM-DD)" },
                "employee_id": { "type": "string", "description": "Employee name or email" },
                "product_id": { "type": "string", "description": "Expense category/product name" },
                "proposal_id": { "type": "string", "description": "A unique tracking ID for this AI proposal" },
                "attachment_base64": { "type": "string", "description": "Base64 encoded file content of the receipt" },
                "attachment_name": { "type": "string", "description": "Filename for the attachment (e.g., 'receipt.pdf')" }
            },
            "required": ["name", "total_amount_currency", "employee_id", "proposal_id"]
        }
